SELECT fabric_name
FROM fabric_types
WHERE composition LIKE '%cotton%';

SELECT fabric_name, description
FROM fabric_types
WHERE fabric_id = 0;

SELECT MAX(value) AS MaximumMeasurementValue
FROM product_measurements
WHERE product_id = 1;

SELECT MAX(total_revenue) AS top_revenue
FROM (
    SELECT SUM(revenue) AS total_revenue
    FROM sales
);
